#include<bits/stdc++.h>
using namespace std;
int shu[1001][2],heng[1001][2],a[1001][1001];
int main()
{
	int n;
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			scanf("%d",&a[i][j]);
			heng[j][i&1]+=a[i][j];
			shu[i][j&1]+=a[i][j];
		}
	}
	int max1=0,max2=0;
	for(int i=1;i<=n;i++)
	{
		max1+=max(heng[i][0],heng[i][1]);
		max2+=max(shu[i][0],shu[i][1]);
	}
	printf("%d",max(max1,max2));
	return 0;
}
